---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"
import ArrowRightIcon from "lucide-static/icons/arrow-right.svg"

import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  badge?: string
  title: string
  description?: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  services: {
    image: {
      src: ImageMetadata
      alt: string
    }
    title: string
    description: string
    href?: string
  }[]
}

const {
  class: className,
  badge,
  title,
  description,
  buttons,
  services,
} = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer
    class="grid gap-8 lg:grid-cols-[20rem_minmax(0,1fr)] lg:items-start"
  >
    <div class="lg:sticky lg:top-28">
      {badge && <Badge variant="secondary">{badge}</Badge>}
      <h2 class="mt-4 text-3xl font-semibold tracking-tight text-balance">
        {title}
      </h2>
      {
        description && (
          <p class="text-muted-foreground mt-4 text-sm leading-relaxed">
            {description}
          </p>
        )
      }
      {
        buttons?.length && (
          <div class="mt-6 flex flex-wrap gap-3">
            {buttons.map(({ href, label, ...button }) => (
              <Button as="a" href={href} variant={button.variant}>
                {label}
              </Button>
            ))}
          </div>
        )
      }
    </div>
    <div class="grid gap-6 sm:grid-cols-2">
      {
        services.map((service) => (
          <div class="group/service relative isolate flex aspect-square flex-col justify-end overflow-hidden rounded-xl bg-black">
            <Image
              src={service.image.src}
              alt={service.image.alt}
              class="absolute inset-0 -z-10 size-full object-cover opacity-60 transition-transform duration-500 group-hover/service:scale-105"
              widths={[320, 480, 640]}
              sizes="(min-width: 1024px) 30vw, (min-width: 640px) 50vw, 100vw"
            />
            <div class="absolute inset-0 -z-10 bg-linear-to-t from-black/70 to-transparent" />
            <div class="flex items-end justify-between gap-4 p-5 text-white">
              <div class="flex flex-col gap-1">
                <h3 class="text-lg font-semibold">{service.title}</h3>
                <p class="text-sm leading-relaxed text-white/75">
                  {service.description}
                </p>
              </div>
              {service.href && (
                <a
                  href={service.href}
                  class="shrink-0 rounded-full bg-white/15 p-2 backdrop-blur-sm transition-colors hover:bg-white/25"
                >
                  <ArrowRightIcon class="size-4 text-white" />
                </a>
              )}
            </div>
          </div>
        ))
      }
    </div>
  </SectionContainer>
</Section>
